import * as React from 'react';
import { graphql, navigate } from 'gatsby';
import { GatsbyImage, getImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';
import Grid from '@mui/material/Grid';
import { Layout } from '../../components/layout';
import { Link } from '../../components/common/link';
import { Navigation } from '../../components/navigation';
import { Seo } from '../../components/seo';
import { categories } from '../../libs/categories';
import { works } from '../../libs/works';

const Page = props => {
  const [category, setCategory] = React.useState();

  const addImageData = ({ name, category, link }) => {
    const data = props.data.allFile.edges.filter(worksThumbnail => {
      return worksThumbnail.node.name === `${name}_00`;
    });

    if (!data || !data[0] || !data[0].node) {
      console.log(name);
      console.log(data);
      return false;
    }

    const node = data[0].node;

    return {
      name,
      category,
      link,
      image: getImage(node)
    };
  };

  const datas = works.map(work => {
    return addImageData(work);
  });

  React.useEffect(() => {
    const param = new URLSearchParams(props.location.search);
    setCategory(param.get('category'));

    setTimeout(() => {
      const scrollY = window.localStorage.getItem('scrollY') || 0;
      window.scroll(0, scrollY);
    }, 100);
  }, [props.location.search]);

  return (
    <Layout>
      <Navigation />
      <Box
        py={10} // header 分
      >
        <Box
          mb={4} // thumbnail の spacing 分
          sx={{
            display: 'flex',
            justifyContent: 'center'
          }}
        >
          {categories.map(({ label, id }, i) => {
            const link = `/works/${id === 'all' ? '' : `?category=${id}`}`;

            const isCurrent =
              (id === 'all' && category === null) || id === category;

            return (
              <Link
                key={i}
                href={link}
                sx={{
                  mx: {
                    md: 4,
                    sm: 2,
                    xs: 1
                  },
                  textDecoration: isCurrent && 'underline',
                  pointerEvents: isCurrent && 'none'
                }}
              >
                {label}
              </Link>
            );
          })}
        </Box>
        <Grid container direction='row' spacing={4}>
          {category !== undefined &&
            datas
              .filter(({ category: thumbnailCategory }) => {
                // ページカテゴリが何か指定されていれば比較し、そうでなければ all とみなして true を返す
                return category ? thumbnailCategory === category : true;
              })
              .map(({ name, link, image }, i) => {
                link += `/${category ? `?category=${category}` : ''}`;

                return (
                  <Grid
                    item
                    key={i}
                    lg={2}
                    md={3}
                    sm={3}
                    xs={6}
                    sx={{
                      transition: 'all 250ms ease-out'
                    }}
                  >
                    <Link
                      href={`/works/${link}`}
                      sx={{
                        display: 'block',
                        width: '100%',
                        height: '100%'
                      }}
                      onClick={e => {
                        e.preventDefault();
                        window.localStorage.setItem('scrollY', window.scrollY);
                        navigate(link);
                      }}
                    >
                      <GatsbyImage
                        image={image}
                        alt={name}
                        layout='fullWidth'
                        placeholder='blurred'
                        style={{
                          pointerEvents: 'none',
                          userSelect: 'none'
                        }}
                      />
                    </Link>
                  </Grid>
                );
              })}
        </Grid>
      </Box>
    </Layout>
  );
};

export default Page;

export const Head = () => <Seo title='WORKS' />;

export const query = graphql`
  {
    allFile(
      filter: {
        relativeDirectory: { eq: "works" }
        name: { regex: "/^.+_00$/" }
      }
    ) {
      edges {
        node {
          childImageSharp {
            gatsbyImageData(width: 400, placeholder: BLURRED)
          }
          name
        }
      }
    }
  }
`;
